function LxCrestGameHandler:OnCrestGameInfoResp(pb)
    if pb.infoObj then
        ModuleCenter.CrestGame:SetCrestInfo(pb.infoObj)
        FireEvent(EventNames.CREST_GAME_UPDATE)
    end
end

function LxCrestGameHandler:OnCrestGameBuffResp(pb)
    if pb.buffs then
        local buffs = {}
        for _, value in ipairs(pb.buffs or {}) do
            table.insert(buffs,value)
        end
        ModuleCenter.CrestGame.selBuffs = buffs
        FireEvent(EventNames.CREST_GAME_BUFF_UPDATE)
    end
end

function LxCrestGameHandler:OnCrestGameBuffSelectResp(pb)
   local buffId = pb.buffId
   if buffId and buffId >0 then
        table.insert(ModuleCenter.CrestGame.buffs,buffId)
        ModuleCenter.CrestGame.selBuffs = {}
   end
    -- FireEvent(EventNames.CREST_COLLECT_UPDATE)
end
--刷新敌人
function LxCrestGameHandler:OnCrestGameEnemyRefreshResp(pb)
    if pb.infoObj then 
        ModuleCenter.CrestGame:SetCrestInfo(pb.infoObj)
        FireEvent(EventNames.CREST_GAME_UPDATE_ROLE)
        ShowSysMsg(I18nText(6256))
    end
end
--重置玩法
function LxCrestGameHandler:OnCrestGameResetResp(pb)
    if pb.infoObj then
        ModuleCenter.CrestGame:SetCrestInfo(pb.infoObj)
        ModuleCenter.CrestGame.selBattleStarRole = 3
        FireEvent(EventNames.CREST_GAME_UPDATE)
        -- FireEvent(EventNames.CREST_GAME_RESET)
        ShowSysMsg(I18nText(6259))
    end
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.CrestGame, pb.starRewardInfo,true)
end
--领取奖励
function LxCrestGameHandler:OnCrestGameStarRewardResp(pb)
    if pb.rewardId then
        ModuleCenter.CrestGame.alreadyGet[pb.rewardId] = pb.rewardId
        FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.CrestGame, pb.rewardInfo)--RewardRecvType.VipGift
        FireEvent(EventNames.CREST_GAME_BOX_RWD)
    end
end
--领取通关奖励
function LxCrestGameHandler:OnCrestGamePassRewardResp(pb)
    if pb.rewardId then
        FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.CrestGame, pb.rewardInfo,true)
    end
end

return LxCrestGameHandler